<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Personal Expense Tracker</title>
<style>
  body{font-family:Arial,Helvetica,sans-serif;margin:20px;}
  form div{margin-bottom:10px;}
  label{display:inline-block;width:80px;}
  input[type=number]{width:120px;}
  select,input[type=date],input[type=text]{width:150px;}
  #form-error{color:red;font-weight:bold;}
  table{border-collapse:collapse;width:100%;margin-top:20px;}
  th,td{text-align:left;padding:8px;border-bottom:1px solid #ddd;}
  .expense{background:#f9f9f9;}
  .exp-del{cursor:pointer;color:red;background:none;border:none;font-size:0.9em;}
  .summary{margin-top:10px;}
</style>
</head>
<body>

<h2>Expense Tracker</h2>

<form id="expense-form">
  <div><label for="amount">Amount:</label><input type="number" step="0.01" id="amount" required></div>
  <div><label for="category">Category:</label>
    <select id="category">
      <option value="groceries">Groceries</option>
      <option value="transport">Transport</option>
      <option value="bills">Bills</option>
      <option value="fun">Fun</option>
    </select></div>
  <div><label for="date">Date:</label><input type="date" id="date" required></div>
  <div><label for="note">Note:</label><input type="text" id="note"></div>
  <button type="submit" id="add-expense">Add Expense</button>
  <div id="form-error"></div>
</form>

<h3>Filters</h3>
<div>
  <label for="filter-category">Category:</label>
  <select id="filter-category">
    <option value="all">All</option>
    <option value="groceries">Groceries</option>
    <option value="transport">Transport</option>
    <option value="bills">Bills</option>
    <option value="fun">Fun</option>
  </select>

  <label for="filter-from">From:</label><input type="date" id="filter-from">
  <label for="filter-to">To:</label><input type="date" id="filter-to">
</div>

<table id="expense-table">
  <thead>
    <tr><th>Amount</th><th>Category</th><th>Date</th><th>Note</th><th></th></tr>
  </thead>
  <tbody></tbody>
</table>

<div class="summary">
  <strong>Total: $<span id="total">0.00</span></strong>
</div>
<div class="summary">
  <div data-cat="groceries" class="cat-total">Groceries: $0.00</div>
  <div data-cat="transport" class="cat-total">Transport: $0.00</div>
  <div data-cat="bills" class="cat-total">Bills: $0.00</div>
  <div data-cat="fun" class="cat-total">Fun: $0.00</div>
</div>

<script>
(() => {
  const STORAGE_KEY = 'expenses';
  let expenses = [];

  // Elements
  const form = document.getElementById('expense-form');
  const amountInput = document.getElementById('amount');
  const categorySelect = document.getElementById('category');
  const dateInput = document.getElementById('date');
  const noteInput = document.getElementById('note');
  const formError = document.getElementById('form-error');

  const filterCategory = document.getElementById('filter-category');
  const filterFrom = document.getElementById('filter-from');
  const filterTo = document.getElementById('filter-to');

  const tableBody = document.querySelector('#expense-table tbody');
  const totalSpan = document.getElementById('total');
  const catTotals = document.querySelectorAll('.cat-total');

  // Load from localStorage
  function loadExpenses() {
    const data = localStorage.getItem(STORAGE_KEY);
    expenses = data ? JSON.parse(data) : [];
  }

  // Save to localStorage
  function saveExpenses() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
  }

  // Render table rows
  function renderTable() {
    tableBody.innerHTML = '';
    const visibleRows = [];
    expenses.slice().reverse().forEach(exp => {
      const tr = document.createElement('tr');
      tr.className = 'expense';
      tr.dataset.id = exp.id;
      tr.dataset.cat = exp.category;
      tr.dataset.date = exp.date;

      tr.innerHTML = `
        <td>$${parseFloat(exp.amount).toFixed(2)}</td>
        <td>${exp.category}</td>
        <td>${exp.date}</td>
        <td>${exp.note || ''}</td>
        <td><button class="exp-del">✕</button></td>
      `;
      tableBody.appendChild(tr);
    });
  }

  // Apply filters and update totals
  function applyFilters() {
    const catFilter = filterCategory.value;
    const fromDate = filterFrom.value;
    const toDate = filterTo.value;

    let total = 0;
    const catSums = {groceries:0, transport:0, bills:0, fun:0};

    document.querySelectorAll('.expense').forEach(row => {
      const matchesCat = (catFilter === 'all') || (row.dataset.cat === catFilter);
      const rowDate = row.dataset.date;
      const afterFrom = !fromDate || rowDate >= fromDate;
      const beforeTo = !toDate || rowDate <= toDate;
      const visible = matchesCat && afterFrom && beforeTo;

      row.style.display = visible ? '' : 'none';

      if (visible) {
        const amt = parseFloat(row.children[0].textContent.replace('$',''));
        total += amt;
        catSums[row.dataset.cat] += amt;
      }
    });

    totalSpan.textContent = total.toFixed(2);
    catTotals.forEach(el => {
      const cat = el.dataset.cat;
      el.textContent = `${cat.charAt(0).toUpperCase()+cat.slice(1)}: $${catSums[cat].toFixed(2)}`;
    });
  }

  // Add expense
  form.addEventListener('submit', e => {
    e.preventDefault();
    const amtVal = amountInput.value.trim();
    const catVal = categorySelect.value;
    const dateVal = dateInput.value;
    const noteVal = noteInput.value.trim();

    if (!amtVal || isNaN(amtVal) || Number(amtVal) <= 0 || !dateVal) {
      formError.textContent = 'Please enter a valid amount and date.';
      return;
    }

    const newExp = {
      id: Date.now().toString(),
      amount: parseFloat(amtVal).toFixed(2),
      category: catVal,
      date: dateVal,
      note: noteVal
    };
    expenses.push(newExp);
    saveExpenses();
    renderTable();
    applyFilters();

    formError.textContent = '';
    amountInput.value = '';
  });

  // Delete expense
  tableBody.addEventListener('click', e => {
    if (e.target.classList.contains('exp-del')) {
      const row = e.target.closest('.expense');
      const id = row.dataset.id;
      expenses = expenses.filter(exp => exp.id !== id);
      saveExpenses();
      renderTable();
      applyFilters();
    }
  });

  // Filter events
  filterCategory.addEventListener('change', applyFilters);
  filterFrom.addEventListener('change', applyFilters);
  filterTo.addEventListener('change', applyFilters);

  // Initialize
  loadExpenses();
  renderTable();
  applyFilters();
})();
</script>
</body>
</html>
